import "./App.css";
import { useState, useEffect } from "react";

function App() {

  /* =========================
     STATE
  ========================= */

  const [tasks, setTasks] = useState(() => {
    const saved = localStorage.getItem("tasks");
    return saved ? JSON.parse(saved) : [];
  });

  const [newTask, setNewTask] = useState("");
  const [newDuration, setNewDuration] = useState(25); // minutes

  const [activeTaskId, setActiveTaskId] = useState(null);

  const [timeLeft, setTimeLeft] = useState(1500); // seconds
  const [isRunning, setIsRunning] = useState(false);
  const [sessionComplete, setSessionComplete] = useState(false);

  const [manualMinutes, setManualMinutes] = useState(25);

  const [showCompletedToday, setShowCompletedToday] = useState(false);


  /* =========================
     HELPERS / FORMATTERS
  ========================= */

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? "0" : ""}${secs}`;
  };

  const formatMinutes = (seconds) => {
    const mins = Math.floor(seconds / 60);
    return `${mins} min`;
  };


  /* =========================
     TASK UTILITIES
  ========================= */

  const getTodayCompletedTasks = () => {
    const today = new Date();

    return tasks.filter(task => {
      if (!task.completed || !task.completedAt) return false;

      const completedDate = new Date(task.completedAt);

      return (
        completedDate.getFullYear() === today.getFullYear() &&
        completedDate.getMonth() === today.getMonth() &&
        completedDate.getDate() === today.getDate()
      );
    });
  };

  const todayCompletedTasks = getTodayCompletedTasks();

  const getTodayFocusTime = () => {
    const today = new Date();
    let total = 0;

    tasks.forEach(task => {
      if (!task.sessions) return;

      task.sessions.forEach(session => {
        const d = new Date(session.date);

        if (
          d.getFullYear() === today.getFullYear() &&
          d.getMonth() === today.getMonth() &&
          d.getDate() === today.getDate()
        ) {
          total += session.duration;
        }
      });
    });

    return total;
  };


  /* =========================
     TASK ACTIONS
  ========================= */

  const addTask = () => {
    if (!newTask.trim()) return;

    const task = {
      id: Date.now(),
      title: newTask,
      duration: newDuration * 60,
      completed: false,
    };

    setTasks([...tasks, task]);
    setNewTask("");
  };

  const deleteTask = (id) => {
    setTasks(tasks.filter((task) => task.id !== id));

    // Reset timer if deleting active task
    if (id === activeTaskId) {
      setActiveTaskId(null);
      setIsRunning(false);
      setTimeLeft(1500);
    }
  };

  const toggleTask = (id) => {
    const updatedTasks = tasks.map(task => {
      if (task.id === id) {
        if (task.completed) {
          return { ...task, completed: false, completedAt: null };
        } else {
          return {
            ...task,
            completed: true,
            completedAt: new Date().toISOString()
          };
        }
      }
      return task;
    });

    setTasks(updatedTasks);
  };


  /* =========================
     TIMER LOGIC
  ========================= */

  const startTimer = () => {
    if (timeLeft > 0) {
      setSessionComplete(false);
      setIsRunning(true);
    }
  };

  const stopTimer = () => {
    setIsRunning(false);
  };

  const resetTimer = () => {
    setIsRunning(false);
    setSessionComplete(false);
    setTimeLeft(1500);
  };

  const finishSession = () => {
    setIsRunning(false);
    setSessionComplete(true);

    if (activeTaskId) {
      const timeSpent =
        (tasks.find(t => t.id === activeTaskId)?.duration || 1500) - timeLeft;

      setTasks(prevTasks =>
        prevTasks.map(task => {
          if (task.id === activeTaskId) {
            return {
              ...task,
              completed: true,
              completedAt: new Date().toISOString(),
              sessions: [
                ...(task.sessions || []),
                {
                  date: new Date().toISOString(),
                  duration: timeSpent
                }
              ]
            };
          }
          return task;
        })
      );
    }

    setTimeLeft(0);
  };


  /* =========================
     EFFECTS
  ========================= */

  // Timer ticking
  useEffect(() => {
    if (!isRunning) return;

    const interval = setInterval(() => {
      setTimeLeft((prev) => {
        if (prev <= 1) {
          clearInterval(interval);
          finishSession();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(interval);
  }, [isRunning]);

  // Persist tasks
  useEffect(() => {
    localStorage.setItem("tasks", JSON.stringify(tasks));
  }, [tasks]);


  /* =========================
     UI
  ========================= */

  return (
    <div style={{ padding: "20px" }}>
      <h1>tbd</h1>

      {/* TASK INPUT */}
      <input
        type="text"
        placeholder="Enter a task"
        value={newTask}
        onChange={(e) => setNewTask(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") addTask();
        }}
      />
      <input
        type="number"
        value={newDuration}
        onChange={(e) => setNewDuration(Number(e.target.value))}
        style={{ width: "60px", marginLeft: "10px" }}
      />
      <button onClick={addTask}>Add Task</button>

      {/* TASK LIST */}
      <ul>
        {tasks.map((task) => (
          <li key={task.id}>
            <input
              type="checkbox"
              checked={task.completed}
              onChange={() => toggleTask(task.id)}
            />

            <span style={{
              textDecoration: task.completed ? "line-through" : "none",
              marginLeft: "8px",
            }}>
              {task.title}
            </span>

            <button
              onClick={() => {
                if (isRunning) return;
                setSessionComplete(false);
                setActiveTaskId(task.id);
                setTimeLeft(task.duration || 1500);
                setIsRunning(true);
              }}
            >
              Focus
            </button>

            <button onClick={() => deleteTask(task.id)}>
              Delete
            </button>
          </li>
        ))}
      </ul>

      {/* TIMER */}
      <h3>{formatTime(timeLeft)}</h3>

      <button onClick={startTimer}>Start</button>
      <button onClick={stopTimer}>Stop</button>
      <button onClick={resetTimer}>Reset</button>

      {/* STATS */}
      <h3>Focus Time Today: {formatMinutes(getTodayFocusTime())}</h3>

    </div>
  );
}

export default App;
